// --- Constantes de Configuração ---
const unsigned long SERIAL_BAUD_RATE = 115200;       // Taxa de baud para comunicação serial.
const unsigned long MESSAGE_SEND_INTERVAL_MS = 2000; // Intervalo entre o envio de mensagens (2 segundos).
const unsigned long MILLIS_PER_SECOND = 1000;        // Fator de conversão de milissegundos para segundos.

// --- Constantes para Mensagens de Texto (Armazenadas em Flash para Economia de SRAM) ---
// O uso de F() no Serial.print() direciona essas strings para a memória Flash (PROGMEM),
// economizando a escassa SRAM do microcontrolador.
const char* const WELCOME_MESSAGE = "\n--- ESP32: Exemplo de Comunicação Serial Não-Bloqueante Iniciado ---";
const char* const BAUD_RATE_MESSAGE_PREFIX = "Taxa de Baud: ";
const char* const INTERVAL_MESSAGE_PREFIX = "Enviando mensagens a cada ";
const char* const INTERVAL_MESSAGE_SUFFIX = " segundos.";
const char* const INSTRUCTION_MESSAGE = "Digite algo no Monitor Serial para ver o eco ou 'R' para resetar o contador.";
const char* const DEVICE_MESSAGE_PREFIX = "ESP32_DEV_PING #"; // Prefixo para as mensagens enviadas.
const char* const TIME_DISPLAY_PREFIX = " (Tempo: ";
const char* const TIME_DISPLAY_SUFFIX = " ms)";
const char* const RECEIVED_CHAR_MESSAGE_PREFIX = "Caractere Recebido: '";
const char* const RECEIVED_CHAR_MESSAGE_MIDDLE = "' (ASCII: ";
const char* const RECEIVED_CHAR_MESSAGE_SUFFIX = ")";
const char* const RESET_COMMAND_MESSAGE = "Comando 'R' recebido. Resetando contador de mensagens...";

// --- Variáveis Globais de Estado ---
unsigned long previousMessageMillis = 0; // Armazena o último momento em que uma mensagem foi enviada.
unsigned int messageCounter = 0;         // Contador de mensagens enviadas.

/**
 * @brief Função de configuração que é executada uma vez ao iniciar o ESP32.
 *        Inicializa a comunicação serial e exibe mensagens de boas-vindas.
 */
void setup() {
  // Inicia a comunicação serial com a taxa de baud definida.
  Serial.begin(SERIAL_BAUD_RATE);

  // Não é necessário um 'delay' aqui para o ESP32; Serial.begin() é geralmente suficiente
  // para configurar o hardware e o buffer de saída.
  // Remoção do delay(10) para aderir estritamente à diretriz de código não-bloqueante.

  // Imprime mensagens de inicialização usando F() para economia de SRAM.
  Serial.println(F(WELCOME_MESSAGE));
  Serial.print(F(BAUD_RATE_MESSAGE_PREFIX));
  Serial.println(SERIAL_BAUD_RATE);
  Serial.print(F(INTERVAL_MESSAGE_PREFIX));
  // Calcula o tempo em segundos e imprime sem criar um objeto String temporário.
  Serial.print(MESSAGE_SEND_INTERVAL_MS / MILLIS_PER_SECOND);
  Serial.println(F(INTERVAL_MESSAGE_SUFFIX)); // Linha corrigida para incluir o sufixo.
  Serial.println(F(INSTRUCTION_MESSAGE));
}

/**
 * @brief Função principal de loop que é executada repetidamente.
 *        Contém a lógica para enviar e receber dados serial de forma não-bloqueante.
 */
void loop() {
  // --- Lógica de Envio de Mensagens Não-Bloqueante ---
  // Obtém o tempo atual em milissegundos desde que o ESP32 iniciou.
  unsigned long currentMillis = millis();

  // Verifica se o intervalo definido para o envio da mensagem foi atingido.
  // currentMillis - previousMessageMillis evita problemas de 'overflow' de millis()
  // que ocorre a cada ~50 dias.
  if (currentMillis - previousMessageMillis >= MESSAGE_SEND_INTERVAL_MS) {
    // Atualiza o tempo da última mensagem enviada para o tempo atual.
    previousMessageMillis = currentMillis;
    messageCounter++; // Incrementa o contador de mensagens.

    // Envia a mensagem serial usando F() para economia de SRAM.
    Serial.print(F(DEVICE_MESSAGE_PREFIX));
    Serial.print(messageCounter);
    Serial.print(F(TIME_DISPLAY_PREFIX));
    Serial.print(currentMillis);
    Serial.println(F(TIME_DISPLAY_SUFFIX));
  }

  // --- Lógica de Leitura Serial Não-Bloqueante ---
  // Verifica se há dados disponíveis para leitura no buffer serial.
  if (Serial.available() > 0) {
    // Lê o caractere de entrada.
    char incomingChar = Serial.read();

    // Imprime o caractere recebido e seu valor ASCII, usando F() para economia de SRAM.
    Serial.print(F(RECEIVED_CHAR_MESSAGE_PREFIX));
    Serial.print(incomingChar);
    Serial.print(F(RECEIVED_CHAR_MESSAGE_MIDDLE));
    Serial.print((int)incomingChar); // Converte o char para int para exibir o valor ASCII.
    Serial.println(F(RECEIVED_CHAR_MESSAGE_SUFFIX));

    // Verifica se o caractere recebido é 'R' ou 'r' para resetar o contador.
    if (incomingChar == 'R' || incomingChar == 'r') {
      Serial.println(F(RESET_COMMAND_MESSAGE));
      messageCounter = 0; // Reseta o contador.
    }
  }

  // --- Outras Tarefas Não-Bloqueantes ---
  // Qualquer outro código que precise ser executado continuamente,
  // como leitura de sensores, comunicação de rede, atualização de display,
  // etc., pode ser colocado aqui.
  // Como as lógicas de envio e recebimento serial são não-bloqueantes,
  // essas outras tarefas podem ser executadas em cada iteração do loop(),
  // sem serem atrasadas pela comunicação serial.
  // Exemplo:
  // readSensorData();
  // updateWebServer();
  // checkButtonPress();
}
